[SysClientCacheDataMethodAttribute(true)]

public display SalesAgreementId agreementConfirmVer(SalesLine _this)
{
    SalesTable salesTable;

    select firstonly ETG_SalesAgreementIdComfirmVer from salesTable
        where salesTable.SalesId == _this.SalesId;

    return salesTable.ETG_SalesAgreementIdComfirmVer;

}
